import java.io.*;
import java.net.*;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;

public class FarmServer {
	    public static void main(String[] args) {
	    	        int port = 5000;
	    	                DateTimeFormatter dtf = DateTimeFormatter.ofPattern("yyyy/MM/dd HH:mm:ss");

	    	                        try (ServerSocket serverSocket = new ServerSocket(port)) {
	    	                        	            System.out.println("--- PHASE 7: ARCHITECTURE HUB ACTIVE ---");

	    	                        	                        while (true) {
	    	                        	                        	                try (Socket clientSocket = serverSocket.accept()) {
	    	                        	                        	                	                    BufferedReader in = new BufferedReader(new InputStreamReader(clientSocket.getInputStream()));
	    	                        	                        	                	                                        String rawData = in.readLine();

	    	                        	                        	                	                                                            if (rawData != null) {
	    	                        	                        	                	                                                            	                        String[] p = rawData.split(",");
	    	                        	                        	                	                                                            	                                                String time = dtf.format(LocalDateTime.now());

	    	                        	                        	                	                                                            	                                                                        // 1. Create the Object
	    	                        	                        	                	                                                            	                                                                                                FarmReport report = new FarmReport(p[0], p[1], p[2], p[3], time);

	    	                        	                        	                	                                                            	                                                                                                                        // 2. Pass to the Database Layer (Today's 2% Task)
	    	                        	                        	                	                                                            	                                                                                                                                                DatabaseHandler.saveReport(report);

	    	                        	                        	                	                                                            	                                                                                                                                                                        // 3. Keep log file as a backup
	    	                        	                        	                	                                                            	                                                                                                                                                                                                try (PrintWriter logger = new PrintWriter(new BufferedWriter(new FileWriter("farm_log.txt", true)))) {
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                            logger.println("ARCHIVED: " + report.toString());
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                    }
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                        }
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                        } catch (IOException e) {
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                        	                    System.out.println("Connection Error: " + e.getMessage());
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                        	                                    }
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                        	                                                }
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                        	                                                        } catch (IOException e) {
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                        	                                                        	            System.out.println("Server Error: " + e.getMessage());
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                        	                                                        	                    }
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                        	                                                        	                        }
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                        	                                                        	                        }
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                        	                                                        	                        
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                        	                                                       
	    	                        	                        	                	                                                            	                                                                                                                                                                                                	                                                                                      
	    	                        	                        	                	                                                            	                                                                                                                                                                                              
	    	                        	                        	                	                                                       
	    	                        	                        	              
	    	                        	                    
	    	                      
	 
